import React,{useState} from 'react';
import './App.css';
import Api from './axios/api';

interface Usuario {
  id: number;
  nome: string;
}

function App() {
const [usuario, setUsuario] =useState<Usuario[]>([{} as Usuario]);
const BuscarTodosUsuarios= async () => {
  console.log("Buscando todos os usuários...");
  await Api.get("",{
    params:{
    planilha:"usuario"
  }
  }
).then((response)=>{
    setUsuario(response.data)
    console.log(response.data);
  }
  )  
  .catch((e)=> console.log(e));
}

  return (
    <div style={container}>
      <h1>Hello Mumi Braids!</h1>
      <h4> Site de Agendamento</h4>     
          <p>   
            {usuario.map((usuario)=>{
              return (
                <div>
                  <h1 > {usuario.nome}</h1>
                  </div>
              )
            })}

          </p>      

      <button onClick={(e)=>BuscarTodosUsuarios()}>  Visuaisar</button>
    </div>
  );
}

export default App;

const container={
  display:"flex",
  color:"black",
  backgroundColor:"red",
  alignItems:"center",
  justifyContent:"center",
 }
